  SELECT category_slug, name, slug, array_agg(DISTINCT alias ORDER BY alias) AS aliases
  FROM food_rows, unnest(aliases) AS alias
  GROUP BY category_slug, name, slug
)
INSERT INTO public.foods (slug, name, category_id, aliases)
SELECT pf.slug, pf.name, fc.id, pf.aliases
FROM prepared_foods pf
LEFT JOIN public.food_categories fc ON fc.slug = pf.category_slug
ON CONFLICT (slug) DO UPDATE
SET aliases = (
  SELECT array_agg(DISTINCT alias ORDER BY alias)
  FROM unnest(public.foods.aliases || excluded.aliases) AS alias
), updated_at = now();

