INSERT INTO public.restaurant_foods (restaurant_id, food_id, source)
SELECT r.id, f.id, 'excel_import'
FROM link_rows lr
JOIN public.restaurants r ON r.slug = lr.rest_slug
JOIN public.foods f ON f.slug = lr.food_slug
ON CONFLICT (restaurant_id, food_id) DO NOTHING;

